#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[101];
    int vowels = 0, consonants = 0;

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; s[i] != '\0'; i++) {
        if (isalpha((unsigned char)s[i])) {
            char c = (char)tolower((unsigned char)s[i]);
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
                vowels++;
            } else {
                consonants++;
            }
        }
    }

    printf("%d %d\n", vowels, consonants);
    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char s[201];
    char out[201];
    int i = 0, j = 0;

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    while (s[i] != '\0') {
        if (s[i] == ' ' || s[i] == '\n') {
            if (s[i] == '\n') {
                break;
            }
            out[j++] = s[i++];
        } else {
            int start = i;
            while (s[i] != '\0' && s[i] != ' ' && s[i] != '\n') {
                i++;
            }
            for (int k = i - 1; k >= start; k--) {
                out[j++] = s[k];
            }
        }
    }

    out[j] = '\0';
    printf("%s\n", out);
    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char s[101];
    int best = 0, current = 0;

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; s[i] != '\0' && s[i] != '\n'; i++) {
        if (i == 0 || s[i] == s[i - 1]) {
            current++;
        } else {
            current = 1;
        }
        if (current > best) {
            best = current;
        }
    }

    printf("%d\n", best);
    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char s[201];
    int seen[256] = {0};

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; s[i] != '\0'; i++) {
        unsigned char c = (unsigned char)s[i];
        if (c == '\n') {
            break;
        }
        if (!seen[c]) {
            putchar(c);
            seen[c] = 1;
        }
    }
    putchar('\n');
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[201];
    int counts[5] = {0, 0, 0, 0, 0};
    int len = 0;

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; ; i++) {
        char c = s[i];
        if (c != '\0' && c != '\n' && isalpha((unsigned char)c)) {
            len++;
        } else {
            if (len > 0) {
                if (len >= 5) {
                    counts[4]++;
                } else {
                    counts[len - 1]++;
                }
                len = 0;
            }
            if (c == '\0' || c == '\n') {
                break;
            }
        }
    }

    printf("%d %d %d %d %d\n", counts[0], counts[1], counts[2], counts[3], counts[4]);
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
