        return 0;
    }

    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '\n') {
            break;
        }
        if (isdigit((unsigned char)s[i])) {
            putchar('#');
        } else {
            putchar(s[i]);
        }
    }
    putchar('\n');
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char a[101], b[101];

    if (fgets(a, sizeof(a), stdin) == NULL) {
        return 0;
    }
    if (fgets(b, sizeof(b), stdin) == NULL) {
        return 0;
    }

    a[strcspn(a, "\n")] = '\0';
    b[strcspn(b, "\n")] = '\0';

    int i = 0;
    while (a[i] != '\0' || b[i] != '\0') {
        if (tolower((unsigned char)a[i]) != tolower((unsigned char)b[i])) {
            printf("NO\n");
            return 0;
        }
        i++;
    }

    printf("YES\n");
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[101];
    char letters[101];
    int n = 0;

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; s[i] != '\0'; i++) {
        if (isalpha((unsigned char)s[i])) {
            letters[n++] = (char)tolower((unsigned char)s[i]);
        }
        if (s[i] == '\n') {
            break;
        }
    }

    int ok = 1;
    for (int i = 0; i < n / 2; i++) {
        if (letters[i] != letters[n - 1 - i]) {
            ok = 0;
            break;
        }
    }

    printf("%s\n", ok ? "YES" : "NO");
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char s[201];

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; s[i] != '\0'; i++) {
        if (s[i] == '\n') {
            break;
        }
        if (isupper((unsigned char)s[i])) {
            putchar((char)('A' + (s[i] - 'A' + 3) % 26));
        } else if (islower((unsigned char)s[i])) {
            putchar((char)('a' + (s[i] - 'a' + 3) % 26));
        } else {
            putchar(s[i]);
        }
    }
    putchar('\n');
    return 0;
}

#include <stdio.h>
#include <string.h>

int main(void) {
    char s[201];
    int seen[256] = {0};

    if (fgets(s, sizeof(s), stdin) == NULL) {
        return 0;
    }

    for (int i = 0; s[i] != '\0'; i++) {
        unsigned char c = (unsigned char)s[i];
        if (c == '\n') {
            break;
        }
        if (seen[c]) {
            putchar(c);
            putchar('\n');
            return 0;
        }
        seen[c] = 1;
    }

    printf("NONE\n");
    return 0;
}
